/*edms.com.toastEditor.service.impl.EdmsToastEditorMapper.insertBoard*/
SELECT SEQ_BOARD.NEXTVAL FROM DUAL
INSERT INTO TB_BOARD ( BOARD_ID, TITLE, CONTENT, REG_DT ) VALUES ( #{boardId, jdbcType=NUMERIC}, #{title, jdbcType=VARCHAR}, #{content, jdbcType=CLOB}, SYSDATE )

/*edms.com.toastEditor.service.impl.EdmsToastEditorMapper.insertImage*/
SELECT SEQ_EDITOR_IMAGE.NEXTVAL FROM DUAL
INSERT INTO TB_EDITOR_IMAGE ( IMAGE_ID, FILE_NAME, CONTENT_TYPE, FILE_SIZE, FILE_DATA, REG_DT ) VALUES ( #{imageId}, #{fileName}, #{contentType}, #{fileSize}, #{fileData, jdbcType=BLOB}, SYSDATE )
